toolCalls.args:
{"command": "# Try the SGen worker addresses with additional options and also check symbol table
ADDR2LINE=aarch64-linux-gnu-addr2line
DEBUG=/tmp/symbols/libmonosgen-2.0.so.debug

# Try with -i for inlined frames
echo "SGen worker frames with -i flag:"
$ADDR2LINE -f -i -e "$DEBUG" 0x2f4b20
echo "---"
$ADDR2LINE -f -i -e "$DEBUG" 0x2f4c84
echo ""

# Check if those addresses are in the symbol table
echo "Checking symbol table near 0x2f4b20:"
aarch64-linux-gnu-nm -C "$DEBUG" 2>/dev/null | sort | awk -v addr="0x2f4b20" '
BEGIN { target = strtonum(addr) }
{ cur = strtonum("0x" $1); if (cur <= target) { prev = $0; prev_addr = cur } }
END { if (prev) print prev " (offset +" target-prev_addr ")" }
'

echo "Checking symbol table near 0x2f4c84:"
aarch64-linux-gnu-nm -C "$DEBUG" 2>/dev/null | sort | awk -v addr="0x2f4c84" '
BEGIN { target = strtonum(addr) }
{ cur = strtonum("0x" $1); if (cur <= target) { prev = $0; prev_addr = cur } }
END { if (prev) print prev " (offset +" target-prev_addr ")" }
'", "description": "Resolve remaining SGen worker frames", "initial_wait": 15}

{"command": "# Use objdump to find the function containing these addresses
OBJDUMP=aarch64-linux-gnu-objdump
DEBUG=/tmp/symbols/libmonosgen-2.0.so.debug

echo "Disassembly around 0x2f4b20:"
$OBJDUMP -d --start-address=0x2f4b00 --stop-address=0x2f4b30 "$DEBUG" 2>/dev/null | head -20

echo ""
echo "Disassembly around 0x2f4c84:"
$OBJDUMP -d --start-address=0x2f4c60 --stop-address=0x2f4c90 "$DEBUG" 2>/dev/null | head -20

echo ""
# Find the function these addresses belong to by looking at symbol table for code symbols
echo "Looking for .text symbols near these addresses:"
aarch64-linux-gnu-nm -n "$DEBUG" 2>/dev/null | grep -i " [tT] " | awk '
{ addr = strtonum("0x" $1) }
addr <= 0x2f4b20 { prev1 = $0; pa1 = addr }
addr <= 0x2f4c84 { prev2 = $0; pa2 = addr }
END {
  print "0x2f4b20 is in: " prev1 " (offset +" (0x2f4b20 - pa1) ")"
  print "0x2f4c84 is in: " prev2 " (offset +" (0x2f4c84 - pa2) ")"
}'", "description": "Find functions for SGen worker addresses", "initial_wait": 30}

arguments.command:
# Check section mapping and try DWARF directly
DEBUG=/tmp/symbols/libmonosgen-2.0.so.debug

echo "Section containing 0x2f4b20:"
aarch64-linux-gnu-readelf -S "$DEBUG" 2>/dev/null | awk '
/\[/ { name=$2; addr=strtonum("0x"$4); size=strtonum("0x"$6) }
addr <= 0x2f4b20 && (addr+size) > 0x2f4b20 { print name, sprintf("0x%x", addr), sprintf("size=0x%x", size) }
'

echo ""
echo "Try DWARF line info lookup:"
aarch64-linux-gnu-readelf --debug-dump=line "$DEBUG" 2>/dev/null | head -5

echo ""
# Try using the stripped binary instead, which has the actual .text
echo "Using stripped binary symbol table:"
